-- Data for supabase_migrations.schema_migrations
INSERT INTO "supabase_migrations"."schema_migrations" ("version", "statements", "name") VALUES ('20240311000000', '["-- Create profiles table\\r\\nCREATE TABLE IF NOT EXISTS public.profiles (\\r\\n  id UUID REFERENCES auth.users ON DELETE CASCADE NOT NULL PRIMARY KEY,\\r\\n  email TEXT UNIQUE NOT NULL,\\r\\n  full_name TEXT,\\r\\n  avatar_url TEXT,\\r\\n  role TEXT DEFAULT ''user'' CHECK (role IN (''user'', ''admin'')),\\r\\n  created_at TIMESTAMPTZ DEFAULT NOW()\\r\\n)", "-- Enable RLS\\r\\nALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY", "-- Profiles Policies\\r\\nCREATE POLICY \\"Public profiles are viewable by everyone.\\" ON public.profiles\\r\\n  FOR SELECT USING (true)", "CREATE POLICY \\"Users can insert their own profile.\\" ON public.profiles\\r\\n  FOR INSERT WITH CHECK (auth.uid() = id)", "CREATE POLICY \\"Users can update own profile.\\" ON public.profiles\\r\\n  FOR UPDATE USING (auth.uid() = id)", "-- Create bookings table\\r\\nCREATE TABLE IF NOT EXISTS public.bookings (\\r\\n  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,\\r\\n  user_id UUID REFERENCES public.profiles(id),\\r\\n  service_id TEXT NOT NULL,\\r\\n  service_name TEXT NOT NULL,\\r\\n  customer_name TEXT NOT NULL,\\r\\n  customer_email TEXT NOT NULL,\\r\\n  customer_phone TEXT,\\r\\n  date DATE NOT NULL,\\r\\n  time TEXT NOT NULL,\\r\\n  status TEXT DEFAULT ''pending'' CHECK (status IN (''pending'', ''confirmed'', ''cancelled'', ''completed'')),\\r\\n  total_price NUMERIC,\\r\\n  notes TEXT,\\r\\n  created_at TIMESTAMPTZ DEFAULT NOW()\\r\\n)", "-- Enable RLS\\r\\nALTER TABLE public.bookings ENABLE ROW LEVEL SECURITY", "-- Bookings Policies\\r\\nCREATE POLICY \\"Users can view their own bookings.\\" ON public.bookings\\r\\n  FOR SELECT USING (auth.uid() = user_id OR user_id IS NULL)", "CREATE POLICY \\"Admins can view all bookings.\\" ON public.bookings\\r\\n  FOR ALL USING (\\r\\n    EXISTS (\\r\\n      SELECT 1 FROM public.profiles\\r\\n      WHERE profiles.id = auth.uid() AND profiles.role = ''admin''\\r\\n    )\\r\\n  )", "CREATE POLICY \\"Anyone can create a booking.\\" ON public.bookings\\r\\n  FOR INSERT WITH CHECK (true)", "-- Function to handle new user creation\\r\\nCREATE OR REPLACE FUNCTION public.handle_new_user()\\r\\nRETURNS TRIGGER AS $$\\r\\nBEGIN\\r\\n  INSERT INTO public.profiles (id, email, full_name, avatar_url)\\r\\n  VALUES (\\r\\n    new.id,\\r\\n    new.email,\\r\\n    new.raw_user_meta_data->>''full_name'',\\r\\n    new.raw_user_meta_data->>''avatar_url''\\r\\n  );\\r\\n  RETURN NEW;\\r\\nEND;\\r\\n$$ LANGUAGE plpgsql SECURITY DEFINER", "-- Trigger to create profile after signup\\r\\nCREATE OR REPLACE TRIGGER on_auth_user_created\\r\\n  AFTER INSERT ON auth.users\\r\\n  FOR EACH ROW EXECUTE PROCEDURE public.handle_new_user()"]', 'init');
